-- ----------------------------
-- Table structure for aiops_metric_data
-- ----------------------------
DROP TABLE IF EXISTS `aiops_metric_data`;
CREATE TABLE `aiops_metric_data`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `resource_id` bigint NOT NULL COMMENT '资源ID，逻辑关联 aiops_resource.id',
  `resource_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源编码',
  `resource_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源名称',
  `resource_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源类型：SERVER / DATABASE / MIDDLEWARE / NETWORK',
  `ip_addr` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '资源IP地址',
  `metric_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标编码，例如 CPU_USAGE',
  `metric_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标名称，例如 CPU使用率',
  `metric_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标类型：CPU / MEMORY / DISK / NETWORK / MYSQL / REDIS',
  `metric_value` decimal(18, 4) NOT NULL COMMENT '指标值',
  `metric_unit` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '指标单位，例如 %、ms、MB、count',
  `threshold_value` decimal(18, 4) NULL DEFAULT NULL COMMENT '告警阈值',
  `alarm_flag` tinyint NOT NULL DEFAULT 0 COMMENT '是否触发告警：0否，1是',
  `collect_time` datetime NOT NULL COMMENT '采集时间',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0正常，1异常',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_resource_id`(`resource_id` ASC) USING BTREE,
  INDEX `idx_resource_code`(`resource_code` ASC) USING BTREE,
  INDEX `idx_resource_type`(`resource_type` ASC) USING BTREE,
  INDEX `idx_ip_addr`(`ip_addr` ASC) USING BTREE,
  INDEX `idx_metric_code`(`metric_code` ASC) USING BTREE,
  INDEX `idx_metric_type`(`metric_type` ASC) USING BTREE,
  INDEX `idx_collect_time`(`collect_time` ASC) USING BTREE,
  INDEX `idx_alarm_flag`(`alarm_flag` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AIOps指标采集数据表' ROW_FORMAT = Dynamic;

