  INDEX `idx_resource_code`(`resource_code` ASC) USING BTREE,
  INDEX `idx_resource_type`(`resource_type` ASC) USING BTREE,
  INDEX `idx_ip_addr`(`ip_addr` ASC) USING BTREE,
  INDEX `idx_root_cause_type`(`root_cause_type` ASC) USING BTREE,
  INDEX `idx_analysis_time`(`analysis_time` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AIOps根因分析记录表' ROW_FORMAT = Dynamic;

