DROP TABLE IF EXISTS `aiops_work_order`;
CREATE TABLE `aiops_work_order`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `work_order_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单编码',
  `alert_event_id` bigint NOT NULL COMMENT '告警事件ID',
  `event_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警事件编码',
  `alert_level` tinyint NOT NULL COMMENT '告警级别：1一般，2重要，3严重',
  `work_order_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单标题',
  `work_order_content` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工单内容',
  `resource_id` bigint NOT NULL COMMENT '资源ID',
  `resource_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源编码',
  `resource_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源名称',
  `resource_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资源类型',
  `ip_addr` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `metric_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标编码',
  `metric_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标名称',
  `metric_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '指标类型',
  `order_status` tinyint NOT NULL DEFAULT 0 COMMENT '工单状态：0待处理，1处理中，2已处理，3已关闭',
  `handler_user_id` bigint NULL DEFAULT NULL COMMENT '处理人用户ID',
  `handler_username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '处理人用户名',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  `handle_result` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '处理结果',
  `close_user_id` bigint NULL DEFAULT NULL COMMENT '关闭人用户ID',
  `close_username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '关闭人用户名',
  `close_time` datetime NULL DEFAULT NULL COMMENT '关闭时间',
  `close_result` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '关闭结果',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0有效，1无效',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_work_order_code`(`work_order_code` ASC) USING BTREE,
  UNIQUE INDEX `uk_alert_event_id`(`alert_event_id` ASC) USING BTREE,
  INDEX `idx_event_code`(`event_code` ASC) USING BTREE,
  INDEX `idx_resource_id`(`resource_id` ASC) USING BTREE,
  INDEX `idx_resource_code`(`resource_code` ASC) USING BTREE,
  INDEX `idx_resource_type`(`resource_type` ASC) USING BTREE,
  INDEX `idx_metric_type`(`metric_type` ASC) USING BTREE,
  INDEX `idx_alert_level`(`alert_level` ASC) USING BTREE,
  INDEX `idx_order_status`(`order_status` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AIOps运维工单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of aiops_work_order
-- ----------------------------

-- ----------------------------
-- Table structure for mine_alarm_event
-- ----------------------------
DROP TABLE IF EXISTS `mine_alarm_event`;
CREATE TABLE `mine_alarm_event`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `event_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警事件编码',
  `rule_id` bigint NOT NULL COMMENT '告警规则ID，逻辑关联 mine_alarm_rule.id',
  `rule_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警规则编码',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警规则名称',
  `sensor_data_id` bigint NOT NULL COMMENT '传感器数据ID，逻辑关联 mine_sensor_data.id',
  `sensor_id` bigint NOT NULL COMMENT '传感器ID，逻辑关联 mine_sensor.id',
  `sensor_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '传感器编码',
  `sensor_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '传感器名称',
  `sensor_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '传感器类型',
  `device_id` bigint NULL DEFAULT NULL COMMENT '所属设备ID，逻辑关联 mine_device.id',
  `area_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属区域',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '安装位置',
  `data_value` decimal(18, 4) NOT NULL COMMENT '触发告警的采集值',
  `threshold_value` decimal(18, 4) NOT NULL COMMENT '触发告警的规则阈值',
  `compare_operator` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '比较符号：GT大于，GE大于等于，LT小于，LE小于等于，EQ等于',
  `alarm_level` tinyint NOT NULL DEFAULT 1 COMMENT '告警级别：1一般，2重要，3严重',
  `alarm_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警标题',
  `alarm_content` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '告警内容',
  `alarm_time` datetime NOT NULL COMMENT '告警时间',
  `handle_status` tinyint NOT NULL DEFAULT 0 COMMENT '处理状态：0未处理，1已确认，2已关闭',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0有效，1无效',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_event_code`(`event_code` ASC) USING BTREE,
  UNIQUE INDEX `uk_rule_data`(`rule_id` ASC, `sensor_data_id` ASC) USING BTREE,
  INDEX `idx_rule_id`(`rule_id` ASC) USING BTREE,
  INDEX `idx_sensor_data_id`(`sensor_data_id` ASC) USING BTREE,
  INDEX `idx_sensor_id`(`sensor_id` ASC) USING BTREE,
  INDEX `idx_sensor_code`(`sensor_code` ASC) USING BTREE,
  INDEX `idx_sensor_type`(`sensor_type` ASC) USING BTREE,
  INDEX `idx_area_name`(`area_name` ASC) USING BTREE,
  INDEX `idx_alarm_level`(`alarm_level` ASC) USING BTREE,
  INDEX `idx_alarm_time`(`alarm_time` ASC) USING BTREE,
  INDEX `idx_handle_status`(`handle_status` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '智能矿山告警事件表' ROW_FORMAT = Dynamic;

