-- ----------------------------
-- Table structure for mine_alarm_rule
-- ----------------------------
DROP TABLE IF EXISTS `mine_alarm_rule`;
CREATE TABLE `mine_alarm_rule`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `rule_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则编码',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则名称',
  `sensor_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '传感器类型，例如 GAS、TEMPERATURE、VIBRATION',
  `compare_operator` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '比较符号：GT大于，GE大于等于，LT小于，LE小于等于，EQ等于',
  `threshold_value` decimal(18, 4) NOT NULL COMMENT '规则阈值',
  `alarm_level` tinyint NOT NULL DEFAULT 1 COMMENT '告警级别：1一般，2重要，3严重',
  `alarm_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警标题',
  `alarm_content` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '告警内容模板',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0启用，1停用',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
