-- ----------------------------
-- Table structure for mine_work_order
-- ----------------------------
DROP TABLE IF EXISTS `mine_work_order`;
CREATE TABLE `mine_work_order`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `work_order_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单编码',
  `alarm_event_id` bigint NOT NULL COMMENT '告警事件ID',
  `event_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '告警事件编码',
  `alarm_level` tinyint NULL DEFAULT NULL COMMENT '告警级别：1一般，2重要，3严重',
  `work_order_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单标题',
  `work_order_content` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工单内容',
  `device_id` bigint NULL DEFAULT NULL COMMENT '设备ID',
  `sensor_id` bigint NULL DEFAULT NULL COMMENT '传感器ID',
  `sensor_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '传感器编码',
  `sensor_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '传感器名称',
  `sensor_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '传感器类型',
  `area_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属区域',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '安装位置',
  `order_status` tinyint NOT NULL DEFAULT 0 COMMENT '工单状态：0待处理，1处理中，2已处理，3已关闭',
  `handler_user_id` bigint NULL DEFAULT NULL COMMENT '处理人ID',
  `handler_username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '处理人用户名',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  `handle_result` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '处理结果',
  `close_user_id` bigint NULL DEFAULT NULL COMMENT '关闭人ID',
  `close_username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '关闭人用户名',
  `close_time` datetime NULL DEFAULT NULL COMMENT '关闭时间',
  `close_result` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '关闭结果',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0有效，1无效',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_work_order_code`(`work_order_code` ASC) USING BTREE,
  UNIQUE INDEX `uk_alarm_event_id`(`alarm_event_id` ASC) USING BTREE,
  INDEX `idx_event_code`(`event_code` ASC) USING BTREE,
  INDEX `idx_sensor_code`(`sensor_code` ASC) USING BTREE,
  INDEX `idx_sensor_type`(`sensor_type` ASC) USING BTREE,
  INDEX `idx_area_name`(`area_name` ASC) USING BTREE,
  INDEX `idx_alarm_level`(`alarm_level` ASC) USING BTREE,
  INDEX `idx_order_status`(`order_status` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '智能矿山工单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of mine_work_order
-- ----------------------------
INSERT INTO `mine_work_order` VALUES (1, 'WO-20260629120130-155439', 10, 'ALM-D94-R2', 2, '温度过高', '中央泵房温度传感器一号 采集值 53.3887℃ 触发规则【温度过高告警】，规则阈值为 40.0000℃。', 2, 2, 'SEN-TEMP-001', '中央泵房温度传感器一号', 'TEMPERATURE', '中央泵房', '中央泵房一号水泵旁', 3, 1, 'admin', '2026-06-29 12:03:44', '已安排检修人员到现场检查，确认传感器数据异常并完成初步处置。', 1, 'admin', '2026-06-29 12:04:08', '现场复核完成，设备运行正常，告警已解除，工单关闭。', 0, 'admin', '2026-06-29 12:01:31', 'admin', '2026-06-29 12:04:08', 0, '闭环完成');

-- ----------------------------
-- Table structure for risk_review_order
-- ----------------------------
DROP TABLE IF EXISTS `risk_review_order`;
CREATE TABLE `risk_review_order`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `review_order_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '审核单编号',
  `transaction_id` bigint NOT NULL COMMENT '交易ID',
  `transaction_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '交易流水号',
  `account_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '账户号',
  `customer_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户ID',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '客户姓名',
  `merchant_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商户ID',
  `merchant_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '商户名称',
  `transaction_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '交易类型',
  `channel` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '交易渠道',
  `amount` decimal(18, 2) NULL DEFAULT NULL COMMENT '交易金额',
  `currency` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'CNY' COMMENT '币种',
  `total_score` int NOT NULL DEFAULT 0 COMMENT '风险总分',
  `risk_level` tinyint NOT NULL DEFAULT 1 COMMENT '风险等级：1低风险，2中风险，3高风险',
  `risk_result` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'REVIEW' COMMENT '风险结果：PASS放行，REVIEW人工审核，REJECT拒绝',
  `review_status` tinyint NOT NULL DEFAULT 0 COMMENT '审核状态：0待审核，1审核通过，2审核拒绝',
  `reviewer_user_id` bigint NULL DEFAULT NULL COMMENT '审核人用户ID',
  `reviewer_username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核人用户名',
  `review_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `review_result` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核意见',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0正常，1异常',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_review_order_code`(`review_order_code` ASC) USING BTREE,
  UNIQUE INDEX `uk_transaction_id`(`transaction_id` ASC) USING BTREE,
  INDEX `idx_transaction_no`(`transaction_no` ASC) USING BTREE,
  INDEX `idx_account_no`(`account_no` ASC) USING BTREE,
  INDEX `idx_customer_id`(`customer_id` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE,
  INDEX `idx_risk_result`(`risk_result` ASC) USING BTREE,
  INDEX `idx_review_status`(`review_status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '风险人工审核单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of risk_review_order
-- ----------------------------
