-- ----------------------------
-- Table structure for risk_rule
-- ----------------------------
DROP TABLE IF EXISTS `risk_rule`;
CREATE TABLE `risk_rule`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `rule_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则编码',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则名称',
  `rule_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则类型：AMOUNT/FREQUENCY/LOCATION/DEVICE/TIME/BLACKLIST',
  `condition_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '条件类型',
  `compare_operator` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '比较操作符：GT/GTE/LT/LTE/EQ/CONTAINS/NIGHT',
  `threshold_value` decimal(18, 2) NULL DEFAULT NULL COMMENT '阈值',
  `risk_level` tinyint NOT NULL DEFAULT 1 COMMENT '风险等级：1低风险，2中风险，3高风险',
  `risk_score` int NOT NULL DEFAULT 0 COMMENT '风险分',
  `rule_content` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '规则内容',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态：0启用，1停用',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'system' COMMENT '创建人',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0未删除，1已删除',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_rule_code`(`rule_code` ASC) USING BTREE,
  INDEX `idx_rule_type`(`rule_type` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '风控规则表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of risk_rule
-- ----------------------------
INSERT INTO `risk_rule` VALUES (1, 'RISK_AMOUNT_10000', '大额交易规则', 'AMOUNT', 'amount', 'GTE', 10000.00, 2, 30, '交易金额大于等于10000元', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：大额交易');
INSERT INTO `risk_rule` VALUES (2, 'RISK_FREQ_3_10MIN', '十分钟高频交易规则', 'FREQUENCY', 'account_no', 'GTE', 3.00, 3, 40, '同一账号10分钟内交易次数大于等于3次', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：高频交易');
INSERT INTO `risk_rule` VALUES (3, 'RISK_LOCATION_OVERSEA', '异地交易规则', 'LOCATION', 'location', 'CONTAINS', NULL, 3, 35, '境外,香港,澳门,港澳', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：异地交易');
INSERT INTO `risk_rule` VALUES (4, 'RISK_DEVICE_ABNORMAL', '异常设备规则', 'DEVICE', 'device_id', 'CONTAINS', NULL, 2, 25, 'UNKNOWN,ROOT,ROOTED,EMULATOR,VIRTUAL', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：异常设备');
INSERT INTO `risk_rule` VALUES (5, 'RISK_TIME_NIGHT', '夜间交易规则', 'TIME', 'transaction_time', 'NIGHT', 23.00, 1, 15, '23:00-06:00 夜间交易', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：夜间交易');
INSERT INTO `risk_rule` VALUES (6, 'RISK_BLACKLIST_CUSTOMER', '黑名单客户规则', 'BLACKLIST', 'customer_id/account_no', 'CONTAINS', NULL, 3, 60, 'CUST_BLACK_001,ACC_BLACK_001', 0, 'system', '2026-07-08 00:40:52', NULL, NULL, 0, 'R3-03 默认规则：黑名单');

